class Solution:
    def maxIceCream(self, costs, coins):
        if not costs:
            return 0
        mx = max(costs)
        bucket = [0] * (mx + 1)
        for c in costs:
            bucket[c] += 1
        bought = 0
        for price in range(1, mx + 1):
            if bucket[price] == 0:
                continue
            if coins < price:
                break
            take = min(bucket[price], coins // price)
            coins -= take * price
            bought += take
            if take < bucket[price]:
                break
        return bought

