var maxIceCream = function(costs, coins) {
    if (costs.length === 0) return 0;
    let mx = 0;
    for (const c of costs) if (c > mx) mx = c;
    const bucket = new Array(mx + 1).fill(0);
    for (const c of costs) bucket[c]++;
    let bought = 0;
    for (let price = 1; price <= mx; price++) {
        if (bucket[price] === 0) continue;
        if (coins < price) break;
        const take = Math.min(bucket[price], Math.floor(coins / price));
        coins -= take * price;
        bought += take;
        if (take < bucket[price]) break;
    }
    return bought;
};
